import Dagre from "@dagrejs/dagre";
import type { Node, Edge } from "@xyflow/react";
import { GRAPH_NODES, GRAPH_EDGES } from "@/lib/generated/skill-graph-data";

export const CATEGORY_HEX: Record<string, string> = {
  backend: "#f59e0b",
  frontend: "#3b82f6",
  testing: "#22c55e",
  security: "#ef4444",
  "ai-llm": "#06b6d4",
  devops: "#f97316",
  product: "#ec4899",
  workflow: "#8b5cf6",
  other: "#64748b",
};

export const NODE_W = 172;
export const NODE_H = 44;

export function layoutGraph(nodes: Node[], edges: Edge[]) {
  const g = new Dagre.graphlib.Graph().setDefaultEdgeLabel(() => ({}));
  g.setGraph({ rankdir: "LR", nodesep: 24, ranksep: 80 });

  nodes.forEach((n) => g.setNode(n.id, { width: NODE_W, height: NODE_H }));
  edges.forEach((e) => g.setEdge(e.source, e.target));

  Dagre.layout(g);

  return nodes.map((n) => {
    const pos = g.node(n.id);
    return {
      ...n,
      position: { x: pos.x - NODE_W / 2, y: pos.y - NODE_H / 2 },
    };
  });
}

/** Hub skills with 3+ dependents or 5+ deps — good focus targets */
export const FOCUS_TARGETS = GRAPH_NODES
  .filter((n) => n.usedByCount >= 3 || n.depCount >= 5)
  .sort(
    (a, b) =>
      b.usedByCount + b.depCount - (a.usedByCount + a.depCount)
  )
  .map((n) => n.id);

/** Set of all skill IDs that participate in at least one edge */
export function getConnectedIds(): Set<string> {
  const ids = new Set<string>();
  GRAPH_EDGES.forEach((e) => {
    ids.add(e.source);
    ids.add(e.target);
  });
  return ids;
}

/** Get neighbor IDs for a given skill (direct deps + dependents) */
export function getNeighborIds(skillId: string): Set<string> {
  const s = new Set<string>([skillId]);
  GRAPH_EDGES.forEach((e) => {
    if (e.source === skillId) s.add(e.target);
    if (e.target === skillId) s.add(e.source);
  });
  return s;
}

